def employeeFreeTime(schedule):
    ints = sorted([i for s in schedule for i in s], key=lambda x: x.start)
    res, end = [], ints[0].end
    for i in ints[1:]:
        if i.start > end: res.append(Interval(end, i.start))
        end = max(end, i.end)
    return res

